# -*- coding: utf-8 -*-\nfrom pathlib import Path\ntext = Path('src/main.ts').read_text(encoding='utf-8')\nstart = text.index('function registerIpc()')\nend = text.index('app.whenReady')\nnew_body = '''function registerIpc() {\n  ipcMain.handle('pick-excel', async () => {\n    const res = await dialog.showOpenDialog({\n      properties: ['openFile'],\n      filters: [{ name: 'Excel', extensions: ['xlsx'] }],\n    })\n    return res.canceled ? null : res.filePaths[0]\n  })\n\n  ipcMain.handle('pick-output-dir', async () => {\n    const res = await dialog.showOpenDialog({\n      properties: ['openDirectory', 'createDirectory'],\n    })\n    return res.canceled ? null : res.filePaths[0]\n  })\n\n  ipcMain.handle('excel:preview', async (_event, excelPath: string) => {\n    if (!excelPath) return []\n    return loadExcelPreview(excelPath)\n  })\n\n  ipcMain.handle(\n    'run-generate',\n    async (_event, payload: { excelPath: string; outputDir: string; selectedRows?: number[] }) => {\n      const templatePath = path.join(\n        process.cwd(),\n        'src',\n        'templates',\n        'notice.hbs.html',\n      )\n      const result = await generatePdfs({\n        excelPath: payload.excelPath,\n        outputDir: payload.outputDir,\n        templatePath,\n        selectedRows: payload.selectedRows,\n      })\n\n      if (result?.ok && Array.isArray(result.results) && result.results.length > 0) {\n        await addPdfHistoryBulk(\n          result.results.map((item) => ({\n            filePath: item.file,\n            rowIndex: item.row,\n            docNo: item.docNo,\n            personName: item.personName,\n          })),\n        )\n      }\n\n      return result\n    },\n  )\n\n  ipcMain.handle('history:list', async (_event, limit?: number) => {\n    return listPdfHistory(limit ?? 100)\n  })\n\n  ipcMain.handle('history:delete', async (_event, ids: number[]) => {\n    if (!Array.isArray(ids) || !ids.length) return\n    const rows = await listPdfHistory(500)\n    const targets = rows.filter((row) => ids.includes(row.id))\n    for (const row of targets) {\n      if (fs.existsSync(row.filePath)) {\n        try:\n          fs.unlinkSync(row.filePath)\n        except Exception:\n          pass\n      }\n    }\n    await deletePdfHistory(ids)\n  })\n\n  ipcMain.handle('history:open', async (_event, filePath: string) => {\n    if (!filePath) return\n    if (!fs.existsSync(filePath)) throw new Error('ĘÄĄĻĄ» Ć£Ą» ¼ö ¾ų½Ą´Ļ´Ł.')\n    await shell.openPath(filePath)\n  })\n\n  ipcMain.handle('window:minimize', () => BrowserWindow.getFocusedWindow()?.minimize())\n  ipcMain.handle('window:toggle-maximize', () => {\n    const win = BrowserWindow.getFocusedWindow()\n    if (!win) return\n    if (win.isMaximized()):\n      win.unmaximize()\n    else:\n      win.maximize()\n  })\n  ipcMain.handle('window:close', () => BrowserWindow.getFocusedWindow()?.close())\n}\n\n'''\ntext = text[:start] + new_body.replace('\r', '') + text[end:]\nPath('src/main.ts').write_text(text, encoding='utf-8')
